@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-600: #6a7282;
  --color-neutral-800: #30363d;
  --color-neutral-950: #000000;
  --color-deep-blue: #0b0f19;
  --color-deep-blue-2: #141c2e;
  --color-pale-blue: #e5e7eb;
  --color-blue: #3080ff;
  --color-blue-2: #364153;
  --color-red: #f85149;
  --color-blue-3: #193cb8;
  --color-blue-4: #155dfc;
  --color-blue-5: #625fff;
  --color-red-2: #fb2c36;
  --color-pink: #f6339a;
  --color-blue-6: #99a1af;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #ffffff;
  --color-ink: #000000;
  --color-text-muted: #6a7282;
  --color-surface: #30363d;
  --color-accent: #0b0f19;
  --color-accent-2: #141c2e;
  --color-accent-3: #e5e7eb;

  --font-sans: "Source Sans Pro", ui-sans-serif, system-ui, sans-serif;
  --font-mono: "IBM Plex Mono", ui-monospace, monospace;

  --text-xs: 0.5rem;
  --text-sm: 0.625rem;
  --text-base: 0.75rem;
  --text-lg: 0.8rem;
  --text-xl: 0.856875rem;
  --text-2xl: 0.875rem;
  --text-3xl: 0.88875rem;
  --text-4xl: 0.9rem;
  --text-5xl: 1rem;
  --text-6xl: 1.05rem;
  --text-7xl: 1.2rem;
  --text-8xl: 1.25rem;

  --font-weight-extralight: 200;
  --font-weight-light: 300;
  --font-weight-normal: 400;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;
  --font-weight-black: 900;

  /* line-heights, sorted tight -> loose */
  --leading-none: 1;
  --leading-tight: 1.2;
  --leading-snug: 1.33;
  --leading-normal: 1.5;
  --leading-relaxed: 1.56;
  --leading-loose: 1.6;
  --leading-looser: 1.71;
  --leading-loosest: 1.75;

  /* letter-spacing, sorted tight -> wide */
  --tracking-tightest: .2em;

  --radius-sm: .1rem;
  --radius-md: 3px;
  --radius-lg: .3125rem;
  --radius-xl: .45rem;
  --radius-2xl: 1.6rem;
  --radius-3xl: 100%;
  --radius-full: 50%;

  /* shadows, sorted by blur */
  --shadow-sm: 0 10px 20px #0000000a,0 2px 6px #0000000a,0 0 1px #0000000a;
  --shadow-md: 0 5px 5px #00000008,0 2px 2px #00000008,0 0 1px #00000008;
  --shadow-lg: 0 3.5px 3.5px #00000002,0 2px 2px #00000002,0 0 1px #00000002;
  --shadow-xl: 0 24px 32px #0000000a,0 16px 24px #0000000a,0 4px 8px #0000000a,0 0 1px #0000000a;

  /* most-used spacing values on the source site (px): 1, 2, 3, 4, 5, 8, 10, 12, 16, 22, 23, 27 */
}

/* dark-mode values mined from the source (native token names) */
@media (prefers-color-scheme: dark) {
  :root {
    --scrollbarBG: #020011;
    --thumbBG: #374151;
    --lightningcss-dark: initial;
    --tw-shadow-color: #ffffff0d;
    --tw-ring-color: var(--color-gray-500);
    --tw-ring-offset-color: #0b0f19;
    --tw-gradient-to: #1e2939b3;
    --tw-gradient-from: var(--color-gray-800);
    --tw-gradient-via: #0b0f19;
    --tw-gradient-position: to bottom;
    --tw-gradient-to-position: 70%;
    --tw-shadow: 0 0 #0000!important;
    --tw-ring-shadow: var(--tw-ring-inset,) 0 0 0 calc(1px + var(--tw-ring-offset-width)) var(--tw-ring-color,oklch(62.3% .188 259.81/.5));
    --tw-brightness: brightness(0%);
    --tw-drop-shadow-size: drop-shadow(0 3px 3px var(--tw-drop-shadow-color,#0000001f));
    --tw-drop-shadow: drop-shadow(var(--drop-shadow-md));
    --tw-grayscale: grayscale(100%);
    --tw-invert: invert(100%);
    --tw-prose-body: var(--tw-prose-invert-body);
    --tw-prose-headings: var(--tw-prose-invert-headings);
    --tw-prose-lead: var(--tw-prose-invert-lead);
    --tw-prose-links: var(--tw-prose-invert-links);
    --tw-prose-bold: var(--tw-prose-invert-bold);
    --tw-prose-counters: var(--tw-prose-invert-counters);
    --tw-prose-bullets: var(--tw-prose-invert-bullets);
    --tw-prose-hr: var(--tw-prose-invert-hr);
    --tw-prose-quotes: var(--tw-prose-invert-quotes);
    --tw-prose-quote-borders: var(--tw-prose-invert-quote-borders);
    --tw-prose-captions: var(--tw-prose-invert-captions);
    --tw-prose-kbd: var(--tw-prose-invert-kbd);
    --tw-prose-kbd-shadows: var(--tw-prose-invert-kbd-shadows);
    --tw-prose-code: var(--tw-prose-invert-code);
    --tw-prose-pre-code: var(--tw-prose-invert-pre-code);
    --tw-prose-pre-bg: var(--tw-prose-invert-pre-bg);
    --tw-prose-th-borders: var(--tw-prose-invert-th-borders);
    --tw-prose-td-borders: var(--tw-prose-invert-td-borders);
    --egress-bar-color: var(--color-gray-200);
    --unattributed-bar-color: var(--color-gray-700);
  }
}

